def solve(*args):
    if not args:
        return "No input provided"

    # Assuming args should contain insurance application details
    for arg in args:
        if not isinstance(arg, dict):
            return "Invalid input type, expected a dictionary"

        required_keys = ['name', 'age', 'policy_type']
        for key in required_keys:
            if key not in arg:
                return f"Missing required key: {key}"

        if not isinstance(arg['name'], str) or not arg['name']:
            return "Invalid name provided"

        if not isinstance(arg['age'], int) or arg['age'] <= 0:
            return "Invalid age provided"

        if arg['policy_type'] not in ['life', 'health', 'auto']:
            return "Invalid policy type provided"

    return "All inputs are valid"
